// Script Continued Below

function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'Reopen') {
		// 2.7.0 | 2021-11-08 | mmcc | DFCT0010645 - Platform Reopen Task button does not open modal for some Views
        // if (g_form.getValue('active') != 'false') {
            // return false;
        // }
		if (g_scratchpad.active != 'false') {
			return false;
		}

        if (isNotActiveParent()) {
            return false;
        }

		var task_id = g_form.getUniqueValue();
		_requestParameters(task_id, formAction, confirmReopenTask);
		return false;
	}
}

function confirmReopenTask(response) {
	var params = {};
	var sParams = response.responseXML.documentElement.getAttribute("answer");
	params = JSON.parse(sParams);
	var _spModal;
	if(typeof spModal != 'undefined'){
		_spModal = spModal;
	}
	var _spUtil;
	if(typeof spUtil != 'undefined'){
		_spUtil = spUtil;
	}

	if(x_153465_discovert.DTech_Task_Actions==undefined){
		ScriptLoader.getScripts(['x_153465_discovert.DTech_Task_Actions.jsdbx'], function() {
			x_153465_discovert.DTech_Task_Actions.confirmReopenTasks(_spModal, _spUtil, g_form, params);
		});
	} else {
		// already loaded, just call it
		x_153465_discovert.DTech_Task_Actions.confirmReopenTasks(_spModal, _spUtil, g_form, params);
	}

	return false;
}

// NOTE: this might be able to be moved into the UI Script if the UI Script has access to GlideAjax
function _requestParameters(task_id, action_name, callback){
	var ajax  = new GlideAjax('ClientTaskInfo');
	ajax.addParam('sysparm_name', 'getTaskUIActionParamaters');
	ajax.addParam('sysparm_task_id', task_id);
	ajax.addParam('sysparm_action_name', action_name);
	ajax.getXML(callback);
}

// Task State 3 = Completed; 4 = Closed Incomplete; 7 = Cancelled should have active = 'false'
// NOTE: the form message is also in the UI Script
function isNotActiveParent(params) {
    var result = false;

    if (g_scratchpad.parent_sys_id + '' != '' && g_scratchpad.parent_active != 'true') {

		// STRY0113839 
		var ga = new GlideAjax("client_tasker_User_Form_Preferences");
		ga.addParam('sysparm_name', 'get_URL_for_Task_Based_on_Prefrences');
		ga.addParam('sysparam_sys_id', g_scratchpad.parent_sys_id);
		ga.addParam('sysparam_current_view', 'sp');
		ga.getXML(function(response){
			var answer = response.responseXML.documentElement.getAttribute("answer");
			var url = answer + '&state=3&order=1';

			g_form.addErrorMessage(" <b>" + getMessage('Tasker - Reopen Parent is not active - start') + " " + '<a href=' + url + '>' +
									g_scratchpad.parent_number + '</a>' + ' ' + getMessage('Tasker - Reopen Parent is not active - end') + '</b>');
		});

        result = true;
    }

    return result;
}
